import Database from 'better-sqlite3';
import type { TariffPlan, User, InterviewSession, Subscription, UserStats } from '@/types';

const DB_PATH = '/home/hermes/projects/ai-interview-trainer/data/interviews.db';

let db: Database.Database | null = null;

export function getDb(): Database.Database {
  if (!db) {
    db = new Database(DB_PATH, { readonly: false });
    db.pragma('journal_mode = WAL');
    db.pragma('foreign_keys = ON');
  }
  return db;
}

export function createAuthToken(telegramId: number, token: string): void {
  const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();
  getDb()
    .prepare(
      'INSERT INTO auth_tokens (telegram_id, token, expires_at) VALUES (?, ?, ?)'
    )
    .run(telegramId, token, expiresAt);
}

export function consumeAuthToken(token: string): { telegramId: number } | null {
  const db = getDb();
  const row = db
    .prepare(
      "SELECT id, telegram_id FROM auth_tokens WHERE token = ? AND used = 0 AND expires_at > datetime('now')"
    )
    .get(token) as { id: number; telegram_id: number } | undefined;
  if (!row) return null;
  db.prepare('UPDATE auth_tokens SET used = 1 WHERE id = ?').run(row.id);
  return { telegramId: row.telegram_id };
}

export function getUserByTelegramId(telegramId: number): User | null {
  const row = getDb()
    .prepare('SELECT * FROM users WHERE telegram_id = ?')
    .get(telegramId) as User | undefined;
  return row ?? null;
}

export function createUser(telegramId: number, username: string | null, firstName: string | null): User {
  const db = getDb();
  const stmt = db.prepare(
    'INSERT INTO users (telegram_id, username, first_name, created_at) VALUES (?, ?, ?, datetime(\'now\'))'
  );
  stmt.run(telegramId, username, firstName);
  return getUserByTelegramId(telegramId)!;
}

export function getActiveTariffs(): TariffPlan[] {
  const stmt = getDb().prepare(
    'SELECT id, name, price, duration_days, features, features_ru, max_interviews_per_day, is_active, created_at, updated_at FROM tariff_plans WHERE is_active = 1 ORDER BY price ASC'
  );
  const rows = stmt.all() as Array<Omit<TariffPlan, 'features' | 'features_ru'> & { features: string; features_ru: string | null }>;
  return rows.map((row) => {
    let features: string[];
    try {
      const parsed = JSON.parse(row.features || '[]');
      features = Array.isArray(parsed) ? parsed : typeof parsed === 'string' ? parsed.split(',').map((s: string) => s.trim()) : [];
    } catch {
      features = typeof row.features === 'string' ? row.features.split(',').map((s) => s.trim()) : [];
    }

    let features_ru: string[] | null = null;
    if (row.features_ru) {
      try {
        const parsed = JSON.parse(row.features_ru);
        features_ru = Array.isArray(parsed) ? parsed : typeof parsed === 'string' ? parsed.split(',').map((s: string) => s.trim()) : null;
      } catch {
        features_ru = row.features_ru.split(',').map((s) => s.trim());
      }
    }

    return {
      ...row,
      features,
      features_ru,
      is_active: Boolean(row.is_active),
    };
  });
}

export function getUserStats(telegramId: number): UserStats {
  const db = getDb();
  const user = db.prepare('SELECT id FROM users WHERE telegram_id = ?').get(telegramId) as { id: number } | undefined;
  if (!user) {
    return { totalInterviews: 0, completedInterviews: 0, avgScore: null, sessionsThisWeek: 0, currentPlan: null, recentSessions: [], interviewsThisMonth: 0, completedThisMonth: 0, avgScoreThisMonth: null };
  }

  const { count: totalInterviews } = db
    .prepare('SELECT COUNT(*) as count FROM sessions WHERE user_id = ?')
    .get(user.id) as { count: number };

  const { count: completedInterviews } = db
    .prepare('SELECT COUNT(*) as count FROM sessions WHERE user_id = ? AND completed = 1')
    .get(user.id) as { count: number };

  const { avg } = db
    .prepare('SELECT AVG(total_score) as avg FROM sessions WHERE user_id = ? AND completed = 1 AND total_score IS NOT NULL')
    .get(user.id) as { avg: number | null };

  const { count: sessionsThisWeek } = db
    .prepare("SELECT COUNT(*) as count FROM sessions WHERE user_id = ? AND started_at >= datetime('now', '-7 days')")
    .get(user.id) as { count: number };

  const { count: interviewsThisMonth } = db
    .prepare("SELECT COUNT(*) as count FROM sessions WHERE user_id = ? AND started_at >= datetime('now', '-30 days')")
    .get(user.id) as { count: number };

  const { count: completedThisMonth } = db
    .prepare("SELECT COUNT(*) as count FROM sessions WHERE user_id = ? AND completed = 1 AND started_at >= datetime('now', '-30 days')")
    .get(user.id) as { count: number };

  const { avg: avgScoreThisMonth } = db
    .prepare("SELECT AVG(total_score) as avg FROM sessions WHERE user_id = ? AND completed = 1 AND total_score IS NOT NULL AND started_at >= datetime('now', '-30 days')")
    .get(user.id) as { avg: number | null };

  const rawSessions = db
    .prepare('SELECT * FROM sessions WHERE user_id = ? ORDER BY started_at DESC LIMIT 5')
    .all(user.id) as Array<Omit<InterviewSession, 'completed'> & { completed: number }>;

  const recentSessions: InterviewSession[] = rawSessions.map((s) => ({
    ...s,
    completed: Boolean(s.completed),
  }));

  const subscription = getUserSubscription(telegramId);

  return {
    totalInterviews,
    completedInterviews,
    avgScore: avg,
    interviewsThisMonth,
    completedThisMonth,
    avgScoreThisMonth,
    sessionsThisWeek,
    currentPlan: subscription ? { name: subscription.plan_name, features: subscription.features } : null,
    recentSessions,
  };
}

export function getUserInterviews(
  telegramId: number,
  page: number,
  perPage: number,
): { sessions: InterviewSession[]; total: number } {
  const db = getDb();
  const user = db.prepare('SELECT id FROM users WHERE telegram_id = ?').get(telegramId) as { id: number } | undefined;
  if (!user) return { sessions: [], total: 0 };

  const { count: total } = db
    .prepare('SELECT COUNT(*) as count FROM sessions WHERE user_id = ?')
    .get(user.id) as { count: number };

  const offset = (page - 1) * perPage;
  const rawSessions = db
    .prepare('SELECT * FROM sessions WHERE user_id = ? ORDER BY started_at DESC LIMIT ? OFFSET ?')
    .all(user.id, perPage, offset) as Array<Omit<InterviewSession, 'completed'> & { completed: number }>;

  const sessions: InterviewSession[] = rawSessions.map((s) => ({
    ...s,
    completed: Boolean(s.completed),
  }));

  return { sessions, total };
}

export function getUserSubscription(telegramId: number): Subscription | null {
  const db = getDb();
  const user = db.prepare('SELECT id FROM users WHERE telegram_id = ?').get(telegramId) as { id: number } | undefined;
  if (!user) return null;

  const row = db
    .prepare(
      `SELECT s.*, tp.name as plan_name, tp.features, tp.features_ru
       FROM subscriptions s
       JOIN tariff_plans tp ON s.tariff_plan_id = tp.id
       WHERE s.user_id = ? AND s.status = 'active' AND s.end_date > datetime('now')
       ORDER BY s.created_at DESC
       LIMIT 1`,
    )
    .get(user.id) as (Omit<Subscription, 'features' | 'features_ru' | 'payment_type'> & { features: string; features_ru: string | null; payment_type: string | null }) | undefined;

  if (!row) return null;

  // Parse features: handle both JSON array and comma-separated string formats
  function parseFeatures(val: string | null): string[] {
    if (!val) return [];
    try {
      const parsed = JSON.parse(val);
      return Array.isArray(parsed) ? parsed : typeof parsed === 'string' ? parsed.split(',').map((s: string) => s.trim()).filter(Boolean) : [];
    } catch {
      return val.split(',').map((s) => s.trim()).filter(Boolean);
    }
  }

  return {
    ...row,
    features: parseFeatures(row.features),
    features_ru: row.features_ru ? parseFeatures(row.features_ru) : null,
  };
}

// ── Company Sets ──────────────────────────────────────────────────────────

export interface CompanySetRow {
  slug: string;
  name_en: string;
  name_ru: string;
  emoji: string | null;
  is_free: number;
}

export function getCompanySets(): CompanySetRow[] {
  return getDb()
    .prepare(
      "SELECT slug, name_en, name_ru, emoji, is_free FROM company_sets WHERE is_active = 1 ORDER BY sort_order"
    )
    .all() as CompanySetRow[];
}

// ── User Companies ────────────────────────────────────────────────────────

export interface UserCompany {
  id: number;
  company_name: string;
  vacancy_url: string;
  position: string;
  ai_context: string;
  created_at: string;
}

export function getUserCompanies(telegramId: number): UserCompany[] {
  const user = getDb()
    .prepare('SELECT id FROM users WHERE telegram_id = ?')
    .get(telegramId) as { id: number } | undefined;
  if (!user) return [];
  return getDb()
    .prepare(
      'SELECT id, company_name, vacancy_url, position, ai_context, created_at FROM user_companies WHERE user_id = ? ORDER BY created_at DESC'
    )
    .all(user.id) as UserCompany[];
}
